arguments.argument:
if global.gamePaused=false
{
  makeEnemyActive(0)
  if bActive=true and stunnedTime=0
  {
    if sprite_index=sSpinyBeetleBall
    {
      if xVel>0
        image_angle-=8
      else
        image_angle+=8
    }
    else
    {
      if initDir=0
      {
        setCollisionBounds(-8,-14,8,-1)
        xVel=runAcc
        if x>oPlayer1.x
          xVel*=-1
        initDir=1
      }
    }
    
    yVel+=0.2
    if isCollisionBottom(1)
    {
      yVel=0
      if sprite_index=sSpinyBeetleBall
      {
        y-=2
        yVel=-1.5
        setCollisionBounds(-8,-14,8,-1)
        sprite_index=sSpinyBeetleWalk
        image_angle=0
        xVel=runAcc
        initDir=1
        if x>oPlayer1.x
          xVel*=-1
      }
    }
    if isCollisionLeft(1)
      xVel*=-1
    if isCollisionRight(1)
      xVel*=-1
    if isCollisionSolid()
      y-=2
    if xVel>0
      image_xscale=1
    else
      image_xscale=-1
    moveTo(xVel,yVel)
    if y>room_height+24
      instance_destroy()
  }
  
  if bActive=false and initDir=1
    instance_destroy()
  enemyStepEvent()
}
